/**
 * TN-LAB Experiment 10: Intrinsic Dimension of H-Space
 * 
 * Scientific Stage v5.6 - Canonical Revision
 * 
 * OBJECTIVE:
 * Determine the intrinsic dimension of the H-space generated by Γ.
 * Although H ∈ ℝ^58, the market dynamics may live in a lower-dimensional subspace.
 * 
 * HYPOTHESIS:
 * The H-space has low intrinsic dimension compared to 58.
 * Expected: 5 ≤ dim_intrinsic ≤ 15
 * 
 * If dim ≈ 58 → chaotic / noise
 * If dim << 58 → structured dynamics
 * 
 * METHODS (3 independent estimators):
 * 1. PCA Intrinsic Dimension: # components for 95% variance
 * 2. Participation Ratio: D = (Σ λ_i)² / Σ (λ_i²)
 * 3. Local Intrinsic Dimension: Levina-Bickel MLE estimator
 * 
 * NO React, NO browser APIs. Pure TypeScript math.
 */

import { SufficientStats, TheoryID, TN_CONSTANTS } from '../engine/types';
import { computeStats } from '../engine/gamma';
import { computePhi } from '../engine/phi';
import { 
  generateTrendingSegment, 
  generateVolatileSegment, 
  generateRangingSegment, 
  generateMixedSegment, 
  SeededRNG 
} from '../simulator/marketData';

/**
 * Convert SufficientStats to continuous feature vector (exclude regime)
 * Returns: number[] of dimension 58
 */
function statsToVector(stats: SufficientStats): number[] {
  const features: number[] = [];
  
  // Core statistics (5)
  features.push(stats.mean);
  features.push(stats.variance);
  features.push(stats.skew);
  features.push(stats.kurtosis);
  features.push(stats.hurst);
  
  // Autocorrelation (20)
  for (let i = 0; i < TN_CONSTANTS.MAX_LAG; i++) {
    features.push(stats.autocorr[i] || 0);
  }
  
  // Spectral density (33) - power values only
  if (stats.spectrum && stats.spectrum.powers) {
    const spectralCount = 33;
    for (let i = 0; i < spectralCount; i++) {
      features.push(stats.spectrum.powers[i] || 0);
    }
  } else {
    // Fill with zeros if no spectrum
    for (let i = 0; i < 33; i++) {
      features.push(0);
    }
  }
  
  return features; // Total: 5 + 20 + 33 = 58
}

/**
 * Apply z-score normalization to each dimension
 */
function zScoreNormalize(vectors: number[][]): { normalized: number[][]; means: number[]; stds: number[] } {
  if (vectors.length === 0) {
    return { normalized: [], means: [], stds: [] };
  }
  
  const dim = vectors[0].length;
  const means: number[] = [];
  const stds: number[] = [];
  
  // Compute mean and std for each dimension
  for (let d = 0; d < dim; d++) {
    let sum = 0;
    for (const v of vectors) {
      sum += v[d];
    }
    const mean = sum / vectors.length;
    
    let sumSq = 0;
    for (const v of vectors) {
      sumSq += (v[d] - mean) ** 2;
    }
    const std = Math.sqrt(sumSq / (vectors.length - 1)) || 1;
    
    means.push(mean);
    stds.push(std);
  }
  
  // Normalize
  const normalized: number[][] = [];
  for (const v of vectors) {
    const norm: number[] = [];
    for (let d = 0; d < dim; d++) {
      norm.push((v[d] - means[d]) / stds[d]);
    }
    normalized.push(norm);
  }
  
  return { normalized, means, stds };
}

/**
 * Compute covariance matrix
 */
function computeCovarianceMatrix(vectors: number[][]): number[][] {
  const n = vectors.length;
  const dim = vectors[0].length;
  
  if (n < 2) return [];
  
  // First compute means
  const means = new Array(dim).fill(0);
  for (const v of vectors) {
    for (let d = 0; d < dim; d++) {
      means[d] += v[d];
    }
  }
  for (let d = 0; d < dim; d++) {
    means[d] /= n;
  }
  
  // Covariance matrix
  const cov: number[][] = [];
  for (let i = 0; i < dim; i++) {
    cov[i] = new Array(dim).fill(0);
    for (let j = 0; j < dim; j++) {
      let sum = 0;
      for (const v of vectors) {
        sum += (v[i] - means[i]) * (v[j] - means[j]);
      }
      cov[i][j] = sum / (n - 1);
    }
  }
  
  return cov;
}

/**
 * Compute eigenvalues of symmetric matrix using power iteration with deflation
 * Returns eigenvalues in descending order
 */
function computeEigenvalues(matrix: number[][], maxIterations: number = 100): number[] {
  const n = matrix.length;
  if (n === 0) return [];
  
  const eigenvalues: number[] = [];
  let A = matrix.map(row => [...row]);
  
  for (let iter = 0; iter < n; iter++) {
    // Power iteration to find largest eigenvalue
    let v = new Array(n).fill(0).map(() => Math.random());
    // Normalize
    let norm = Math.sqrt(v.reduce((s, x) => s + x * x, 0));
    v = v.map(x => x / norm);
    
    let eigenvalue = 0;
    
    for (let i = 0; i < maxIterations; i++) {
      // A * v
      const Av = new Array(n).fill(0);
      for (let row = 0; row < n; row++) {
        for (let col = 0; col < n; col++) {
          Av[row] += A[row][col] * v[col];
        }
      }
      
      // Compute eigenvalue (Rayleigh quotient)
      const vAv = v.reduce((s, x, i) => s + x * Av[i], 0);
      const vv = v.reduce((s, x) => s + x * x, 0);
      eigenvalue = vAv / vv;
      
      // Update v
      norm = Math.sqrt(Av.reduce((s, x) => s + x * x, 0));
      if (norm < 1e-10) break;
      v = Av.map(x => x / norm);
    }
    
    eigenvalues.push(eigenvalue);
    
    // Deflation: A = A - λ * v * v^T
    for (let i = 0; i < n; i++) {
      for (let j = 0; j < n; j++) {
        A[i][j] -= eigenvalue * v[i] * v[j];
      }
    }
  }
  
  return eigenvalues.sort((a, b) => b - a); // Descending order
}

/**
 * METHOD 1: PCA Intrinsic Dimension
 * Number of components that explain 95% of variance
 */
function computePCADimension(vectors: number[][]): number {
  const cov = computeCovarianceMatrix(vectors);
  if (cov.length === 0) return 0;
  
  const eigenvalues = computeEigenvalues(cov);
  if (eigenvalues.length === 0) return 0;
  
  const totalVariance = eigenvalues.reduce((sum, e) => sum + Math.max(0, e), 0);
  if (totalVariance < 1e-10) return 0;
  
  let cumVariance = 0;
  for (let i = 0; i < eigenvalues.length; i++) {
    cumVariance += Math.max(0, eigenvalues[i]);
    if (cumVariance / totalVariance >= 0.95) {
      return i + 1;
    }
  }
  
  return eigenvalues.length;
}

/**
 * METHOD 2: Participation Ratio
 * D = (Σ λ_i)² / Σ (λ_i²)
 * Measures how many axes really contribute
 */
function computeParticipationRatio(vectors: number[][]): number {
  const cov = computeCovarianceMatrix(vectors);
  if (cov.length === 0) return 0;
  
  const eigenvalues = computeEigenvalues(cov);
  if (eigenvalues.length === 0) return 0;
  
  const posEigenvalues = eigenvalues.filter(e => e > 0);
  if (posEigenvalues.length === 0) return 0;
  
  const sumLambda = posEigenvalues.reduce((s, e) => s + e, 0);
  const sumLambdaSq = posEigenvalues.reduce((s, e) => s + e * e, 0);
  
  if (sumLambdaSq < 1e-10) return 0;
  
  return (sumLambda * sumLambda) / sumLambdaSq;
}

/**
 * METHOD 3: Local Intrinsic Dimension (Levina-Bickel MLE)
 * D = [ (1/(k-1)) Σ log(T_k / T_i) ]⁻¹
 * where T_i = distance to i-th neighbor
 * 
 * Fixed implementation with better numerical stability
 */
function computeLocalDimension(vectors: number[][], k: number = 10): number {
  const n = vectors.length;
  if (n < k + 1) return 0;
  
  // Precompute all pairwise distances
  const distances: number[][] = [];
  for (let i = 0; i < n; i++) {
    distances[i] = [];
    for (let j = 0; j < n; j++) {
      if (i === j) {
        distances[i][j] = Infinity;
      } else {
        let sum = 0;
        for (let d = 0; d < vectors[i].length; d++) {
          sum += (vectors[i][d] - vectors[j][d]) ** 2;
        }
        distances[i][j] = Math.sqrt(sum);
      }
    }
  }
  
  // For each point, compute local dimension using k-nearest neighbors
  const dimensions: number[] = [];
  
  for (let i = 0; i < n; i++) {
    // Find k nearest neighbors (excluding self)
    const sorted = distances[i]
      .map((d, idx) => ({ dist: d, idx }))
      .filter(p => p.idx !== i)
      .sort((a, b) => a.dist - b.dist);
    
    const neighbors = sorted.slice(0, k);
    if (neighbors.length < k) continue;
    
    // T_k = distance to k-th neighbor
    const Tk = neighbors[k - 1].dist;
    if (Tk < 1e-10) continue;
    
    // Compute sum of log ratios for i = 1 to k-1
    let sumLog = 0;
    let validCount = 0;
    for (let j = 0; j < k - 1; j++) {
      const Ti = neighbors[j].dist;
      if (Ti > 1e-10 && Ti < Tk) {
        sumLog += Math.log(Tk / Ti);
        validCount++;
      }
    }
    
    // Levina-Bickel formula: D = (k-1) / Σ log(T_k / T_i)
    if (validCount > 0 && sumLog > 0) {
      const D = (k - 1) / sumLog;
      if (D > 0 && D < 100) { // Reasonable range
        dimensions.push(D);
      }
    }
  }
  
  if (dimensions.length === 0) return 0.1;
  
  // Return median for robustness
  dimensions.sort((a, b) => a - b);
  const median = dimensions[Math.floor(dimensions.length / 2)];
  
  return Math.max(0.1, Math.min(58, median));
}

/**
 * Generate trajectory of H vectors over time
 */
function generateHTrajectory(
  prices: number[],
  windowSize: number,
  stepSize: number
): SufficientStats[] {
  const trajectory: SufficientStats[] = [];
  
  for (let i = 0; i + windowSize < prices.length; i += stepSize) {
    const window = prices.slice(i, i + windowSize);
    const stats = computeStats(window);
    trajectory.push(stats);
  }
  
  return trajectory;
}

/**
 * Compute Φ for trajectory (average)
 */
function computeAveragePhi(trajectory: SufficientStats[], prices: number[]): number {
  let totalPhi = 0;
  let count = 0;
  
  const windowSize = 500;
  for (let i = windowSize; i < prices.length; i += 50) {
    const window = prices.slice(i - windowSize, i);
    if (window.length >= windowSize) {
      const idx = Math.floor((i - windowSize) / 50);
      if (idx < trajectory.length) {
        const phi = computePhi(0 as TheoryID, trajectory[idx], window);
        totalPhi += phi.phi;
        count++;
      }
    }
  }
  
  return count > 0 ? totalPhi / count : 0;
}

/**
 * Run intrinsic dimension analysis for a regime
 */
function analyzeRegime(
  prices: number[],
  windowSize: number,
  stepSize: number
): {
  pcaDimension: number;
  participationRatio: number;
  localDimension: number;
  phi: number;
  sampleSize: number;
} {
  // Generate H trajectory
  const trajectory = generateHTrajectory(prices, windowSize, stepSize);
  
  // Convert to vectors
  const vectors = trajectory.map(stats => statsToVector(stats));
  
  if (vectors.length < 10) {
    return {
      pcaDimension: 0,
      participationRatio: 0,
      localDimension: 0,
      phi: 0,
      sampleSize: vectors.length,
    };
  }
  
  // Normalize
  const { normalized } = zScoreNormalize(vectors);
  
  // Compute dimensions
  const pcaDimension = computePCADimension(normalized);
  const participationRatio = computeParticipationRatio(normalized);
  const localDimension = computeLocalDimension(normalized, 10);
  
  // Compute Φ
  const phi = computeAveragePhi(trajectory, prices);
  
  return {
    pcaDimension,
    participationRatio,
    localDimension,
    phi,
    sampleSize: normalized.length,
  };
}

/**
 * Main experiment runner
 */
export function runIntrinsicDimensionExperiment(): {
  pass: boolean;
  results: {
    trending: {
      pcaDimension: number;
      participationRatio: number;
      localDimension: number;
      phi: number;
      sampleSize: number;
    };
    volatile: {
      pcaDimension: number;
      participationRatio: number;
      localDimension: number;
      phi: number;
      sampleSize: number;
    };
    ranging: {
      pcaDimension: number;
      participationRatio: number;
      localDimension: number;
      phi: number;
      sampleSize: number;
    };
    mixed: {
      pcaDimension: number;
      participationRatio: number;
      localDimension: number;
      phi: number;
      sampleSize: number;
    };
  };
  hypothesis: boolean;
  metric: string;
  validationDetails: {
    pcaLessThan58: boolean;
    prSimilarToPCA: boolean;
    localSimilarToPCA: boolean;
  };
  phiDimensionCorrelation: number;
} {
  console.log('\n=== EXPERIMENT 10: Intrinsic Dimension of H-Space ===\n');
  
  const rng = new SeededRNG(42);
  const windowSize = 200;
  const stepSize = 5;
  const length = 10000;
  
  // Generate trajectories for each regime
  console.log(`Generating market trajectories (N=${length})...`);
  
  const trendingPrices = generateTrendingSegment(length, 100, rng);
  const volatilePrices = generateVolatileSegment(length, 100, rng);
  const rangingPrices = generateRangingSegment(length, 100, rng);
  const mixedPrices = generateMixedSegment(length, 100, rng);
  
  // Analyze each regime
  console.log('Computing intrinsic dimensions...\n');
  
  const trending = analyzeRegime(trendingPrices, windowSize, stepSize);
  const volatile = analyzeRegime(volatilePrices, windowSize, stepSize);
  const ranging = analyzeRegime(rangingPrices, windowSize, stepSize);
  const mixed = analyzeRegime(mixedPrices, windowSize, stepSize);
  
  // Print results table
  console.log('INTRINSIC DIMENSION RESULTS:');
  console.log('=============================');
  console.log('Regime     | PCA Dim | PR Dim  | Local Dim | Φ     | N');
  console.log('-----------|---------|---------|-----------|-------|-----');
  console.log(`Trending   | ${trending.pcaDimension.toFixed(1).padStart(7)} | ${trending.participationRatio.toFixed(1).padStart(7)} | ${trending.localDimension.toFixed(1).padStart(9)} | ${trending.phi.toFixed(3)} | ${trending.sampleSize}`);
  console.log(`Volatile   | ${volatile.pcaDimension.toFixed(1).padStart(7)} | ${volatile.participationRatio.toFixed(1).padStart(7)} | ${volatile.localDimension.toFixed(1).padStart(9)} | ${volatile.phi.toFixed(3)} | ${volatile.sampleSize}`);
  console.log(`Ranging    | ${ranging.pcaDimension.toFixed(1).padStart(7)} | ${ranging.participationRatio.toFixed(1).padStart(7)} | ${ranging.localDimension.toFixed(1).padStart(9)} | ${ranging.phi.toFixed(3)} | ${ranging.sampleSize}`);
  console.log(`Mixed      | ${mixed.pcaDimension.toFixed(1).padStart(7)} | ${mixed.participationRatio.toFixed(1).padStart(7)} | ${mixed.localDimension.toFixed(1).padStart(9)} | ${mixed.phi.toFixed(3)} | ${mixed.sampleSize}`);
  
  // Validation criteria
  const pcaLessThan58 = trending.pcaDimension < 58 && volatile.pcaDimension < 58 && 
                        ranging.pcaDimension < 58 && mixed.pcaDimension < 58;
  
  const avgPCA = (trending.pcaDimension + volatile.pcaDimension + ranging.pcaDimension + mixed.pcaDimension) / 4;
  const avgPR = (trending.participationRatio + volatile.participationRatio + ranging.participationRatio + mixed.participationRatio) / 4;
  const avgLocal = (trending.localDimension + volatile.localDimension + ranging.localDimension + mixed.localDimension) / 4;
  
  const prSimilarToPCA = Math.abs(avgPR - avgPCA) / avgPCA < 0.3;
  const localSimilarToPCA = Math.abs(avgLocal - avgPCA) / avgPCA < 0.3;
  
  console.log('\nVALIDATION CRITERIA:');
  console.log(`  PCA < 58: ${pcaLessThan58 ? '✅' : '❌'}`);
  console.log(`  PR ~ PCA (±30%): ${prSimilarToPCA ? '✅' : '❌'} (PR=${avgPR.toFixed(1)}, PCA=${avgPCA.toFixed(1)})`);
  console.log(`  Local ~ PCA (±30%): ${localSimilarToPCA ? '✅' : '❌'} (Local=${avgLocal.toFixed(1)}, PCA=${avgPCA.toFixed(1)})`);
  
  // Compute correlation between Φ and dimension (exploratory)
  const phiValues = [trending.phi, volatile.phi, ranging.phi, mixed.phi];
  const dimValues = [trending.pcaDimension, volatile.pcaDimension, ranging.pcaDimension, mixed.pcaDimension];
  
  const n = 4;
  let sumPhi = 0, sumD = 0, sumPhiD = 0, sumPhi2 = 0, sumD2 = 0;
  for (let i = 0; i < n; i++) {
    sumPhi += phiValues[i];
    sumD += dimValues[i];
    sumPhiD += phiValues[i] * dimValues[i];
    sumPhi2 += phiValues[i] ** 2;
    sumD2 += dimValues[i] ** 2;
  }
  
  const phiDimensionCorrelation = (n * sumPhiD - sumPhi * sumD) / 
                                   Math.sqrt((n * sumPhi2 - sumPhi ** 2) * (n * sumD2 - sumD ** 2) + 1e-10);
  
  console.log(`\nΦ-DIMENSION CORRELATION (exploratory): ${phiDimensionCorrelation.toFixed(3)}`);
  
  // Hypothesis: validation criteria are met
  const hypothesis = pcaLessThan58 && prSimilarToPCA && localSimilarToPCA;
  
  console.log(`\nHYPOTHESIS: ${hypothesis ? 'PASS ✅' : 'FAIL ❌'}`);
  
  return {
    pass: hypothesis,
    results: {
      trending,
      volatile,
      ranging,
      mixed,
    },
    hypothesis,
    metric: `PCA avg: ${avgPCA.toFixed(1)}, PR avg: ${avgPR.toFixed(1)}, Local avg: ${avgLocal.toFixed(1)}`,
    validationDetails: {
      pcaLessThan58,
      prSimilarToPCA,
      localSimilarToPCA,
    },
    phiDimensionCorrelation,
  };
}

// Run if called directly
if (require.main === module) {
  const result = runIntrinsicDimensionExperiment();
  console.log('\n=== FINAL RESULT ===');
  console.log(`Status: ${result.pass ? 'PASS ✅' : 'FAIL ❌'}`);
  console.log(`Metric: ${result.metric}`);
}
